typedef enum SDL_AsyncIOResult
{
 SDL_ASYNCIO_COMPLETE, /**< تعاد هذه القيمة عندما يكتمل طلب SDL_AsyncIO بنجاح، وعند ظهورها يفهم التطبيق أن العملية انتهت من دون خطأ إضافي. */
 SDL_ASYNCIO_FAILURE, /**< تعاد هذه القيمة عندما يفشل طلب SDL_AsyncIO، وعند ظهورها يجب فحص SDL_GetError() لمعرفة سبب الفشل قبل متابعة المعالجة. */
 SDL_ASYNCIO_CANCELED /**< تعاد هذه القيمة عندما يُلغى طلب SDL_AsyncIO قبل اكتماله، وعند ظهورها لا تكون العملية قد وصلت إلى نتيجتها الطبيعية. */
} SDL_AsyncIOResult;
